import { TZDateMini } from '@date-fns/tz';
import { addDays, startOfDay } from 'date-fns';
import { useMemo, type ReactNode } from 'react';
import { useIntl } from 'react-intl';

import type { TimeValue } from '@dynatrace-sdk/units';
import { getTimezone } from '@dynatrace-sdk/user-preferences';

import { getFormattedTimeValue } from '../../../core/time/helpers.js';
import { useTimeframeSelectorStore } from '../../../core/time/timeframeStore/useTimeframeStore.js';
import {
  formatTimeValue,
  formatTimeframe,
  parseValue,
  getTimeValue,
} from '../../../forms/forms-core/time/timeParser.js';
import { getTextFromNode } from '../../filter/utils/getTextFromNode.js';
import { TIMEFRAME_SELECTOR_MESSAGES } from '../constants/timeframeSelectorMessages.js';
import { formatTimeframeDuration } from '../utils/formatting.js';
import { isTimeframeOrFromToString } from '../utils/timeframe-selection.js';

//#region Typings
interface UseTooltipValues {
  timeframeDisplayValue: ReactNode;
  tooltipFormattedTimeValueStart: string;
  tooltipFormattedTimeValueEnd: string;
  formattedPresetItemValue: string;
  timeframeDuration: string;
  isAbsoluteTimeframe: boolean;
  isInvalid: boolean;
}
//#endregion

/**
 * Hook used to retrieve the formatted values shown in the Tooltips of the Button, stepper and PresetItems.
 * @Internal
 */
export function useTooltipMessages(
  value: {
    from: TimeValue | string | null;
    to: TimeValue | string | null;
  } | null,
  children?: ReactNode,
): UseTooltipValues {
  const intl = useIntl();

  const { from, to } = parseValue(value);
  const isFullDay = useTimeframeSelectorStore((state) => state.isFullDay);
  const precision = useTimeframeSelectorStore((state) => state.precision);

  const isAbsoluteTimeframe =
    from?.type === 'iso8601' && to?.type === 'iso8601';

  const startTime = intl.formatMessage(TIMEFRAME_SELECTOR_MESSAGES.startTime);
  const endTime = intl.formatMessage(TIMEFRAME_SELECTOR_MESSAGES.endTime);
  const duration = intl.formatMessage(TIMEFRAME_SELECTOR_MESSAGES.duration);

  const tooltipFormattedTimeValueStart = useMemo(
    () => `${startTime}: ${getFormattedTimeValue(from, precision)}`,
    [from, precision, startTime],
  );

  const tooltipFormattedTimeValueEnd = useMemo(
    () => `${endTime}: ${getFormattedTimeValue(to, precision)}`,
    [endTime, precision, to],
  );

  const formattedPresetItemValue = useMemo(
    () =>
      `${formatTimeValue(from, precision)} → ${formatTimeValue(to, precision)}`,
    [precision, from, to],
  );

  const { displayValue, isInvalid } = useMemo(
    () =>
      isTimeframeOrFromToString(value)
        ? formatTimeframe(value, intl, precision)
        : {
            displayValue: '',
            isInvalid: true,
          },
    [value, intl, precision],
  );

  const timeframeDisplayValue = useMemo(
    () => getTextFromNode(children, intl, '') || displayValue,
    [children, displayValue, intl],
  );
  // use start of next day when selected over calendar.
  const adjustedTo =
    isFullDay && to?.absoluteDate
      ? getTimeValue(
          startOfDay(
            addDays(new TZDateMini(to.absoluteDate, getTimezone()), 1),
          ).toISOString(),
        ) ?? to
      : to;

  const timeframeDuration = useMemo(
    () => `${duration}: ${formatTimeframeDuration(from, adjustedTo, intl)}`,
    [duration, from, adjustedTo, intl],
  );

  return {
    timeframeDisplayValue,
    tooltipFormattedTimeValueStart,
    tooltipFormattedTimeValueEnd,
    formattedPresetItemValue,
    timeframeDuration,
    isAbsoluteTimeframe,
    isInvalid,
  };
}
